<script>
        if (window.SR7?.B?.initForms) SR7.B.initForms();
        (function() {            
                const label = document.getElementById('svg-hover-label');
                const iconset = document.getElementById('iconset');

                if (!label || !iconset) return;                
                iconset.addEventListener('mouseover', e => {

                    const svg = e.target.closest('svg');
                    if (!svg) return;

                    let id = svg.getAttribute('id') || svg.querySelector('use')?.getAttribute('xlink:href') || '';

                    if (id.startsWith('#')) id = id.substring(1);

                    if (id) {
                        label.textContent = id;
                        label.style.opacity = 1;
                    }
                });

                iconset.addEventListener('mouseout', e => {
                    const svg = e.target.closest('svg');
                    if (!svg) return;

        label.style.opacity = 0;
    });
})();

    document.addEventListener('DOMContentLoaded', () => {
        // 1) Get all symbols from your sprite
        const sprite = document.querySelector('#iconset'); // adjust selector if needed
        const symbols = sprite ? Array.from(sprite.querySelectorAll('svg[id]')) : [];
        
        // --- Sort symbols by their id ---
        symbols.sort((a, b) => a.id.localeCompare(b.id));

        // Re-append in sorted order (this actually changes DOM order)
        symbols.forEach(sym => sprite.appendChild(sym));


        // Optional: if you have a list/grid of icon previews, sort that too
        // assuming each preview element has data-symbol-id=""
        const list = document.querySelector('.sr-icon-list'); // container for previews
        if (list) {
            const items = Array.from(list.querySelectorAll('.sr-icon-item'));
            items.sort((a, b) => {
                return a.dataset.symbolId.localeCompare(b.dataset.symbolId);
            });
            items.forEach(item => list.appendChild(item));
        }

        // 2) Click handler to copy SVG snippet to clipboard
        // Here I assume each preview contains a <use> pointing to the symbol        
        symbols.forEach(symbol => {
            symbol.addEventListener('click', () => {                                                
                const id = symbol.id;
                                

                // Parse viewBox → [minX, minY, width, height]
                const viewBox = symbol.getAttribute('viewBox') || '0 0 24 24';
                const parts = viewBox.split(/\s+/);
                const width  = parts[2] || 24;
                const height = parts[3] || 24;

                // Build the snippet
                const snippet =
                    `<svg class="sr--icon" width="${width}" height="${height}" transform="translate(0, 0)">` +
                        `<use xlink:href="#${id}"></use>` +
                    `</svg>`;

                console.log(snippet);
                // Copy to clipboard
                if (navigator.clipboard && navigator.clipboard.writeText) {
                    navigator.clipboard.writeText(snippet).catch(err => {
                        console.warn('Clipboard error:', err);
                    });
                } else {
                    // Fallback for older browsers
                    const ta = document.createElement('textarea');
                    ta.value = snippet;
                    document.body.appendChild(ta);
                    ta.select();
                    document.execCommand('copy');
                    document.body.removeChild(ta);
                }

                // Optional: small UI feedback
                // showToast(`Copied: ${id}`);
            });
        });
    });
        
    </script>